/**
 * Calculate the mainType and objectType from objectTypeId and add the properties to the
 * hand in object.
 *
 * @param selectedObject The object to extend
 */
function addObjectTypeAndMainType(selectedObject) {
    if (isTypelessDocument(selectedObject.objectTypeId)) {
        selectedObject.objectTypeId = "-1";
    }

    // In WebClient it is a string. Therefore toString();
    selectedObject.mainType = (selectedObject.objectTypeId >>> 16).toString();

    switch (selectedObject.mainType) {
        case "0": selectedObject.objectType = "FOLDER"; break;
        case "99": selectedObject.objectType = "REGISTER"; break;
        default: selectedObject.objectType = "DOCUMENT"; break;
    }
}

/**
 * Return true if we are running inside a modal dialog. If we are running inside a dashlet the return is false.
 */
function isModalDialog() {
    return modalDialog;
}

/**
 * This function is only for the unit-tests to reset the rich client library to its original state
 */
function reset() {
    modalDialog = false;
    onInitCallback = () => {};
    onUpdateCallback = () => {};
    dashletCache = null;
    lastSelectionSignature = "";
    lastMappedDashletData = null;
    stopSelectionMonitor();

    delete window.osClient;
}

function getLocationInfo(data) {
    // Priority: register location if available, otherwise folder location,
    // otherwise return empty object.
    // folder is at the root - no parent information available
    if (data.folderid === data.objectident && data.foldertype === data.objecttype) {
        return {};
    }
    
    // registers inside the root folder
    if (
        data.objectident === data.registerid &&
        data.objecttype === data.registertype
    ) {
        return {
            objectId: data.folderid,
            objectTypeId: data.foldertype
        };
    }

    // If registerid/registertype are present, use them
    if (data.registerid != null && data.registertype != null) {
        return {
            objectId: data.registerid,
            objectTypeId: data.registertype
        };
    }

    // If folderid/foldertype are present, use them
    if (data.folderid != null && data.foldertype != null) {
        return {
            objectId: data.folderid,
            objectTypeId: data.foldertype
        };
    }

    // Fallback to empty object
    return {};
}

function createMappedLastSelectedEntry(lastSelectedEntry) {
    if (!lastSelectedEntry) {
        return {
            hasVariants: null,
            mainType: 0,
            objectTypeId: "",
            osid: "",
            objectType: "UNKNOWN"
        };
    }

    return {
        hasVariants: null,
        mainType: lastSelectedEntry.mainType,
        objectTypeId: lastSelectedEntry.objectTypeId,
        osid: lastSelectedEntry.objectId,
        objectType: lastSelectedEntry.objectType
    };
}

function createMappedSelectedEntries(selectedEntries) {
    return selectedEntries.map(selectedEntry => ({
        osid: selectedEntry.objectId,
        objectTypeId: selectedEntry.objectTypeId,
        objectType: selectedEntry.objectType,
        mainType: selectedEntry.mainType
    }));
}

function getMappedSelectionSignature(mappedSelectedEntries) {
    return mappedSelectedEntries.map(entry => `${entry.osid},${entry.objectTypeId}`).join(";");
}

function resolveFollowUpLastSelectedEntry(selectedEntries, previousMappedData) {
    // On synthetic monitor updates there is no "clicked item" event payload.
    // Keep the previous lastSelectedEntry if it is still selected.
    const previousOsId = previousMappedData?.lastSelectedEntry?.osid;
    if (previousOsId) {
        const previousMatch = selectedEntries.find(entry => entry.objectId === previousOsId);
        if (previousMatch) {
            return previousMatch;
        }
    }

    return selectedEntries.length > 0 ? selectedEntries[0] : null;
}

function mergeMappedDataWithSelection(previousMappedData, selectedEntries) {
    // Reuse previous mapped payload and only replace selection-dependent fields.
    // This keeps session/user/context fields stable for consumers.
    const mappedSelectedEntries = createMappedSelectedEntries(selectedEntries);
    const nextLastSelectedEntry = resolveFollowUpLastSelectedEntry(selectedEntries, previousMappedData);
    const mappedLastSelectedEntry = createMappedLastSelectedEntry(nextLastSelectedEntry);

    const mergedMappedData = {
        ...previousMappedData,
        selectedEntries: mappedSelectedEntries,
        lastSelectedEntry: mappedLastSelectedEntry
    };

    if (mergedMappedData.osDashletInit && nextLastSelectedEntry) {
        mergedMappedData.osDashletInit = {
            ...mergedMappedData.osDashletInit,
            objectident: nextLastSelectedEntry.objectId,
            objecttype: nextLastSelectedEntry.objectTypeId
        };
    }

    return mergedMappedData;
}

function isKarmaEnvironment() {
    return typeof window !== "undefined" && window.__karma__ != null;
}

function startSelectionMonitor() {
    if (selectionMonitorIntervalId != null || isKarmaEnvironment()) {
        return;
    }

    // Safety net: rich client can miss or delay a deselection update.
    // Polling keeps dashlet selection in sync without user action.
    const MONITOR_INTERVAL_MS = 250;
    selectionMonitorIntervalId = setInterval(async () => {
        if (
            selectionMonitorInFlight ||
            onUpdateCallback == null ||
            modalDialog ||
            !window.osClient ||
            lastMappedDashletData == null
        ) {
            return;
        }

        selectionMonitorInFlight = true;
        try {
            const currentRead = await getSelectedObjects();
            const currentSignature = getSelectionSignature(currentRead);
            if (currentSignature === lastSelectionSignature) {
                return;
            }

            const mergedMappedData = mergeMappedDataWithSelection(lastMappedDashletData, currentRead);
            const mergedSignature = getMappedSelectionSignature(mergedMappedData.selectedEntries);
            if (mergedSignature === lastSelectionSignature) {
                return;
            }


            lastSelectionSignature = mergedSignature;
            lastMappedDashletData = mergedMappedData;
            onUpdateCallback(mergedMappedData);
        } catch {
        } finally {
            selectionMonitorInFlight = false;
        }
    }, MONITOR_INTERVAL_MS);

}

function stopSelectionMonitor() {
    if (selectionMonitorIntervalId == null) {
        return;
    }

    clearInterval(selectionMonitorIntervalId);
    selectionMonitorIntervalId = null;
    selectionMonitorInFlight = false;
}

async function normalizeStaleRichClientSelection(selectedEntries, data, isInitEvent) {
    if (isInitEvent || selectedEntries.length <= 1) {
        // Init events and single-select events are usually stable immediately.
        return selectedEntries;
    }

    // Rich-client selection can lag behind update events. A single follow-up read is often still stale.
    // We perform short retries and use the latest stable snapshot.
    const MAX_RETRIES = 4;
    const MIN_RETRIES_BEFORE_STABLE = 2;
    const RETRY_DELAY_MS = 35;
    const reads = [selectedEntries];
    let previousSignature = getSelectionSignature(selectedEntries);

    for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
        await sleep(RETRY_DELAY_MS);
        const read = await getSelectedObjects();
        const signature = getSelectionSignature(read);
        reads.push(read);


        if (signature === previousSignature && attempt >= MIN_RETRIES_BEFORE_STABLE) {
            const preferredStableRead = preferReadContainingPayload(reads, data.objectident);
            return preferredStableRead;
        }

        previousSignature = signature;
    }

    const selectedRead = preferReadContainingPayload(reads, data.objectident);

    return selectedRead;
}

function getSelectionSignature(selectedEntries) {
    return selectedEntries.map(entry => `${entry.objectId},${entry.objectTypeId}`).join(";");
}

function preferReadContainingPayload(reads, payloadObjectId) {
    // Prefer a snapshot that contains the payload primary object.
    // If none match, use the newest snapshot.
    for (let index = reads.length - 1; index >= 0; index--) {
        const read = reads[index];
        if (read.some(entry => entry.objectId === payloadObjectId)) {
            return read;
        }
    }

    return reads[reads.length - 1];
}

function sleep(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
}

// Export functions to be used in other JavaScript files.
// Ref: https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Statements/import
export {
	registerOnInitCallback, 
	registerOnUpdateCallback, 
	sendToRichClient,
	isModalDialog,

    // Only for Unit-Tests
    registerOnInitUpdate,	
    reset
};
